      text-align: center;
      padding: 48px 16px 32px;
    }

    h1 {
      font-size: 40px;
      font-weight: 600;
      margin: 0;
      letter-spacing: 0.5px;
    }

    .subtitle {
      font-size: 18px;
      color: var(--text-muted);
      margin-top: 8px;
    }

