      box-shadow: 0 8px 24px rgba(0, 0, 0, 0.4);
    }

    .card-title {
      font-size: 20px;
      font-weight: 600;
      margin: 0 0 8px;
    }

    .card-desc {
      font-size: 15px;
      color: var(--text-muted);
      flex-grow: 1;
      margin-bottom: 16px;
    }

    .btn {
      align-self: flex-start;
      background: var(--primary);
      color: #fff;
      border: none;
      border-radius: 6px;
      padding: 8px 16px;
      font-size: 14px;
      cursor: pointer;
      transition: background 0.2s;
